mapper.select:
SELECT 
FROM ds_payment_order
WHERE third_party_order_no = #{thirdPartyOrderNo}

  AND platform = #{platform}

LIMIT 1

mapper.insert:
INSERT INTO ds_payment_order (
    order_no, customer_no, wallet_no, amount, platform, payment_method,
    third_party_order_no, third_party_transaction_no, payment_params,
    callback_data, status, paid_time, expire_time, notify_url, return_url, ext, remark, biz_no, biz_type, create_time, update_time
) VALUES (
    #{orderNo}, #{customerNo}, #{walletNo}, #{amount}, #{platform}, #{paymentMethod},
    #{thirdPartyOrderNo}, #{thirdPartyTransactionNo}, #{paymentParams},
    #{callbackData}, #{status}, #{paidTime}, #{expireTime}, #{notifyUrl}, #{returnUrl}, #{ext}, #{remark}, #{bizNo}, #{bizType}, #{createTime}, #{updateTime}
)

mapper.select:
SELECT 
FROM ds_payment_order
WHERE status = 'PENDING'
  AND expire_time < #{currentTime}
ORDER BY expire_time ASC

LIMIT #{limit}

SELECT 
FROM ds_payment_order
WHERE create_time BETWEEN #{startTime} AND #{endTime}

  AND customer_no = #{customerNo}


  AND status = #{status}


  AND platform = #{platform}

ORDER BY create_time DESC, id DESC

choose.when:
SELECT status, COUNT(*) as id, SUM(amount) as amount
FROM ds_payment_order
WHERE 1=1

  AND create_time >= #{startTime}


  AND create_time <= #{endTime}


  AND customer_no = #{customerNo}

GROUP BY status
ORDER BY status

SELECT platform, COUNT(*) as id, SUM(amount) as amount
FROM ds_payment_order
WHERE 1=1

  AND create_time >= #{startTime}


  AND create_time <= #{endTime}


  AND customer_no = #{customerNo}

GROUP BY platform
ORDER BY platform

choose.otherwise:
SELECT status, COUNT(*) as id, SUM(amount) as amount
FROM ds_payment_order
WHERE 1=1

  AND create_time >= #{startTime}


  AND create_time <= #{endTime}


  AND customer_no = #{customerNo}

GROUP BY status
ORDER BY status

mapper.select:
SELECT COUNT(*)
FROM ds_payment_order
WHERE order_no = #{orderNo}

mapper.update:
UPDATE ds_payment_order SET status = 'EXPIRED', update_time = CURRENT_TIMESTAMP WHERE order_no IN
#{orderNo}
AND status = 'PENDING'

mapper.select:
SELECT 
FROM ds_payment_order t


        AND t.order_no LIKE CONCAT('%', #{orderNo}, '%')


        AND t.customer_no = #{customerNo}


        AND t.status = #{status}


        AND t.platform = #{platform}


        AND t.create_time >= #{startTime}


        AND t.create_time <= #{endTime}


ORDER BY t.create_time DESC

SELECT 
FROM ds_payment_order
WHERE platform = #{platform}
  AND create_time BETWEEN #{startTime} AND #{endTime}
